using Microsoft.Extensions.Logging;

namespace MyMauiApp;

public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .ConfigureFonts(fonts =>
            {
                fonts.AddFont("OpenSans-Regular.ttf", "OpenSansRegular");
            });

        // 1. Data service — Singleton
        // HttpClient and its base address are expensive to create and should
        // be reused. A single DataService instance also gives you a
        // consistent in-memory cache / shared state across the whole app.
        builder.Services.AddSingleton<IDataService, DataService>();

        // 2. ViewModels — Transient
        // Each navigation to a page should get a fresh ViewModel so stale
        // data from a previous visit never leaks through. Transient means a
        // new instance every time one is requested.
        builder.Services.AddTransient<MainViewModel>();
        builder.Services.AddTransient<DetailViewModel>();

        // 3. Pages — Transient
        // Pages are paired 1-to-1 with their ViewModel. Making them
        // transient keeps the two lifetimes in sync and avoids holding
        // on to heavy UI trees that aren't on screen.
        builder.Services.AddTransient<MainPage>();
        builder.Services.AddTransient<DetailPage>();

#if DEBUG
        builder.Logging.AddDebug();
#endif

        return builder.Build();
    }
}

